    "verbose": { pt: "Se `TRUE`, exibe mensagens de progresso. PadrûÈo `TRUE`.", en: "If `TRUE`, prints progress messages. Default `TRUE`.", es: "Si es `TRUE`, muestra mensajes de progreso. Predeterminado `TRUE`." },
