  "sus_climate_inmet": {
    "years": { pt: "O ano ou anos a importar, por exemplo `2020`, `2020:2024` ou `c(2019, 2021, 2023)`. Deve estar entre 2000 e o ano atual. Se `NULL`, importa os û¤ltimos 2 anos.", en: "The year or years to import, for example `2020`, `2020:2024`, or `c(2019, 2021, 2023)`. Must be between 2000 and the current year. If `NULL`, the last 2 years are imported.", es: "El aûÝo o aûÝos a importar, por ejemplo `2020`, `2020:2024` o `c(2019, 2021, 2023)`. Debe estar entre 2000 y el aûÝo actual. Si es `NULL`, se importan los û¤ltimos 2 aûÝos." },
    "uf": { pt: "Cû°digos de estados brasileiros (por exemplo, `\"AM\"`, `c(\"RJ\", \"MG\")`), sem distinûÏûÈo entre maiû¤sculas e minû¤sculas. Se `NULL` (padrûÈo), importa todos os 27 estados (pode ser lento, ver Desempenho).", en: "Brazilian state codes (e.g. `\"AM\"`, `c(\"RJ\", \"MG\")`), not case sensitive. If `NULL` (default), all 27 states are imported (this may be slow, see Performance).", es: "Cû°digos de estados brasileûÝos (por ejemplo, `\"AM\"`, `c(\"RJ\", \"MG\")`), sin distinciû°n entre mayû¤sculas y minû¤sculas. Si es `NULL` (predeterminado), se importan los 27 estados (puede ser lento, ver Rendimiento)." },
    "station_code": { pt: "Cû°digos de estaûÏûçes do INMET para filtrar (por exemplo, `c(\"A101\", \"A122\")`). Opcional. Se informado, a funûÏûÈo baixa os dados dos `years`/`uf` solicitados e depois mantûˋm apenas as estaûÏûçes especificadas. Se `NULL` (padrûÈo), retorna todas as estaûÏûçes dos estados selecionados. Os cû°digos de estaûÏûÈo sûÈo comparados sem distinûÏûÈo entre maiû¤sculas e minû¤sculas.", en: "INMET station codes to filter by (e.g. `c(\"A101\", \"A122\")`). Optional. If given, the function downloads the data for the requested `years`/`uf` and then keeps only the specified stations. If `NULL` (default), all stations in the selected states are returned. Station codes are matched without regard to case.", es: "Cû°digos de estaciones del INMET para filtrar (por ejemplo, `c(\"A101\", \"A122\")`). Opcional. Si se indica, la funciû°n descarga los datos de los `years`/`uf` solicitados y luego conserva solo las estaciones especificadas. Si es `NULL` (predeterminado), devuelve todas las estaciones de los estados seleccionados. Los cû°digos de estaciû°n se comparan sin distinciû°n entre mayû¤sculas y minû¤sculas." },
    "use_cache": { pt: "Se `TRUE` (padrûÈo), usa dois nûÙveis de cache: um cache de sessûÈo em memû°ria (baseado em um hash MD5 dos parûÂmetros) e um cache em disco (arquivos Parquet com compressûÈo Zstandard). Use `unlink(cache_dir, recursive = TRUE)` para limpar todos os caches.", en: "If `TRUE` (default), uses two levels of caching: a session cache in memory (based on an MD5 hash of the parameters) and a disk cache (Parquet files with Zstandard compression). Use `unlink(cache_dir, recursive = TRUE)` to clear all caches.", es: "Si es `TRUE` (predeterminado), usa dos niveles de cachûˋ: un cachûˋ de sesiû°n en memoria (basado en un hash MD5 de los parûÀmetros) y un cachûˋ en disco (archivos Parquet con compresiû°n Zstandard). Use `unlink(cache_dir, recursive = TRUE)` para borrar todos los cachûˋs." },
    "cache_dir": { pt: "Caminho do diretû°rio para o cache em disco. PadrûÈo: `\"~/.climasus4r_cache/climate\"`. û criado automaticamente.", en: "Directory path for the disk cache. Default: `\"~/.climasus4r_cache/climate\"`. It is created automatically.", es: "Ruta del directorio para el cachûˋ en disco. Predeterminado: `\"~/.climasus4r_cache/climate\"`. Se crea automûÀticamente." },
    "parallel": { pt: "Se `TRUE` (padrûÈo), ativa dois nûÙveis de processamento paralelo: entre anos (vûÀrios anos baixados ao mesmo tempo) e dentro de um ano (os arquivos CSV de cada ano lidos em paralelo). Em importaûÏûçes de um û¤nico ano, aplica-se apenas a paralelizaûÏûÈo dentro do ano.", en: "If `TRUE` (default), enables two levels of parallel processing: across years (several years downloaded at the same time) and within a year (the CSV files of each year parsed in parallel). For single-year imports, only within-year parallelization applies.", es: "Si es `TRUE` (predeterminado), activa dos niveles de procesamiento paralelo: entre aûÝos (varios aûÝos descargados al mismo tiempo) y dentro de un aûÝo (los archivos CSV de cada aûÝo leûÙdos en paralelo). En importaciones de un solo aûÝo, solo se aplica la paralelizaciû°n dentro del aûÝo." },
    "workers": { pt: "Nû¤mero de processos paralelos (workers), como nû¤mero inteiro. PadrûÈo: `4`. Ignorado se `parallel = FALSE`. Usa o backend `future::multisession` e ûˋ automaticamente limitado a `availableCores() - 1`.", en: "Number of parallel workers, as a whole number. Default: `4`. Ignored if `parallel = FALSE`. Uses the `future::multisession` backend and is automatically capped at `availableCores() - 1`.", es: "Nû¤mero de procesos paralelos (workers), como nû¤mero entero. Predeterminado: `4`. Se ignora si `parallel = FALSE`. Usa el backend `future::multisession` y se limita automûÀticamente a `availableCores() - 1`." },
    "lang": { pt: "Idioma das mensagens: `\"pt\"` portuguûˆs (padrûÈo), `\"en\"` inglûˆs ou `\"es\"` espanhol.", en: "Language for messages: `\"pt\"` Portuguese (default), `\"en\"` English, or `\"es\"` Spanish.", es: "Idioma de los mensajes: `\"pt\"` portuguûˋs (predeterminado), `\"en\"` inglûˋs o `\"es\"` espaûÝol." },
    "verbose": { pt: "Se `TRUE` (padrûÈo), exibe o progresso detalhado, incluindo acertos e falhas de cache, progresso do download com tentativas de repetiûÏûÈo, alteraûÏûçes de controle de qualidade (linhas corrigidas ou removidas) e estatûÙsticas finais.", en: "If `TRUE` (default), prints detailed progress, including cache hits and misses, download progress with retry attempts, quality-control changes (rows corrected or removed), and final statistics.", es: "Si es `TRUE` (predeterminado), muestra el progreso detallado, incluyendo aciertos y fallos de cachûˋ, progreso de la descarga con reintentos, cambios de control de calidad (filas corregidas o eliminadas) y estadûÙsticas finales." },
  },
