    "station_code": { pt: "Opcional. Restringe o grûÀfico a um cû°digo de estaûÏûÈo especûÙfico.", en: "Optional. Restricts the plot to a specific station code.", es: "Opcional. Restringe el grûÀfico a un cû°digo de estaciû°n especûÙfico." },
