    "type": { pt: "Tipo de grûÀfico a gerar: `\"timeline\"` (uma linha do tempo estilo Gantt dos eventos de onda de calor), `\"calendar\"` (um mapa de calor em calendûÀrio mostrando os dias com ondas de calor), `\"intensity\"` (um grûÀfico de dispersûÈo de duraûÏûÈo versus intensidade, o pico do EHF) ou `\"trend\"` (um grûÀfico de barras com o nû¤mero de eventos por ano).", en: "Type of plot to generate: `\"timeline\"` (a Gantt-style timeline of heatwave events), `\"calendar\"` (a calendar heatmap showing days with heatwaves), `\"intensity\"` (a scatter plot of duration versus intensity, the EHF peak), or `\"trend\"` (a bar chart of the number of events per year).", es: "Tipo de grûÀfico a generar: `\"timeline\"` (una lûÙnea de tiempo estilo Gantt de los eventos de ola de calor), `\"calendar\"` (un mapa de calor en calendario que muestra los dûÙas con olas de calor), `\"intensity\"` (un grûÀfico de dispersiû°n de duraciû°n frente a intensidad, el pico del EHF) o `\"trend\"` (un grûÀfico de barras con el nû¤mero de eventos por aûÝo)." },
    "station_code": { pt: "Opcional. Restringe o grûÀfico a um cû°digo de estaûÏûÈo especûÙfico.", en: "Optional. Restricts the plot to a specific station code.", es: "Opcional. Restringe el grûÀfico a un cû°digo de estaciû°n especûÙfico." },
    "method": { pt: "Opcional. Restringe o grûÀfico a um mûˋtodo especûÙfico (por exemplo `\"EHF\"` ou `\"INMET\"`).", en: "Optional. Restricts the plot to a specific method (for example `\"EHF\"` or `\"INMET\"`).", es: "Opcional. Restringe el grûÀfico a un mûˋtodo especûÙfico (por ejemplo `\"EHF\"` o `\"INMET\"`)." },
    "year": { pt: "Opcional. Restringe o grûÀfico a um ano especûÙfico (û¤til para grûÀficos de calendûÀrio).", en: "Optional. Restricts the plot to a specific year (useful for calendar plots).", es: "Opcional. Restringe el grûÀfico a un aûÝo especûÙfico (û¤til para grûÀficos de calendario)." },
    "interactive": { pt: "Se `TRUE`, retorna um grûÀfico interativo em Plotly; se `FALSE`, retorna um grûÀfico estûÀtico em ggplot2. O padrûÈo ûˋ `TRUE`.", en: "If `TRUE`, returns an interactive Plotly chart; if `FALSE`, returns a static ggplot2 chart. Default is `TRUE`.", es: "Si es `TRUE`, devuelve un grûÀfico interactivo en Plotly; si es `FALSE`, devuelve un grûÀfico estûÀtico en ggplot2. El valor predeterminado es `TRUE`." },
    "color_palette": { pt: "Nome da paleta de cores ggsci a ser usada. O padrûÈo ûˋ `\"npg\"`.", en: "Name of the ggsci color palette to use. Default is `\"npg\"`.", es: "Nombre de la paleta de colores ggsci a usar. El valor predeterminado es `\"npg\"`." },
    "lang": { pt: "Idioma para os rû°tulos e tûÙtulos: `\"en\"` (inglûˆs), `\"pt\"` (portuguûˆs) ou `\"es\"` (espanhol). O padrûÈo ûˋ `\"en\"`.", en: "Language for labels and titles: `\"en\"` (English), `\"pt\"` (Portuguese) or `\"es\"` (Spanish). Default is `\"en\"`.", es: "Idioma para las etiquetas y tûÙtulos: `\"en\"` (inglûˋs), `\"pt\"` (portuguûˋs) o `\"es\"` (espaûÝol). El valor predeterminado es `\"en\"`." },
    "save_plot": { pt: "Caminho de arquivo opcional para salvar o grûÀfico (por exemplo `\"plot.html\"` ou `\"plot.png\"`).", en: "Optional file path for saving the plot (for example `\"plot.html\"` or `\"plot.png\"`).", es: "Ruta de archivo opcional para guardar el grûÀfico (por ejemplo `\"plot.html\"` o `\"plot.png\"`)." },
