    "system": { pt: "O sistema de informaûÏûÈo em saû¤de de onde baixar. Veja a lista de sistemas disponûÙveis.", en: "The health information system to download from. See the list of available systems.", es: "El sistema de informaciû°n en salud desde el cual descargar. Vea la lista de sistemas disponibles." },
    "backend": { pt: "O motor de processamento dos dados. Use `\"arrow\"` para processamento fora da memû°ria e sob demanda (recomendado para grandes volumes de dados), ou `\"tibble\"` para processamento em memû°ria (recomendado para conjuntos de dados pequenos a mûˋdios).", en: "The data processing engine. Use `\"arrow\"` for out-of-memory, lazy processing (recommended for large datasets), or `\"tibble\"` for in-memory processing (recommended for small to medium datasets).", es: "El motor de procesamiento de datos. Use `\"arrow\"` para procesamiento fuera de memoria y bajo demanda (recomendado para grandes volû¤menes de datos), o `\"tibble\"` para procesamiento en memoria (recomendado para conjuntos de datos pequeûÝos a medianos)." },
    "city": { pt: "Nomes de municûÙpios (por exemplo `\"Porto Velho\"`, `\"SûÈo Paulo\"`). Maiû¤sculas/minû¤sculas sûÈo ignoradas e acentos sûÈo normalizados; erros de digitaûÏûÈo geram sugestûçes. Combinado (uniûÈo) com `municipality_code` e aplicado apû°s o download ao conjunto de dados combinado.", en: "Municipality names (for example `\"Porto Velho\"`, `\"SûÈo Paulo\"`). Case is ignored and accents are normalized; typos trigger suggestions. Combined (union) with `municipality_code`, and applied after download to the combined dataset.", es: "Nombres de municipios (por ejemplo `\"Porto Velho\"`, `\"SûÈo Paulo\"`). No distingue mayû¤sculas/minû¤sculas y normaliza los acentos; los errores de escritura generan sugerencias. Se combina (uniû°n) con `municipality_code` y se aplica tras la descarga al conjunto de datos combinado." },
    "municipality_code": { pt: "Cû°digos de municûÙpio de 6 ou 7 dûÙgitos (IBGE). Aplicado de forma independente de `city`; tanto a forma de 6 dûÙgitos (DATASUS) quanto a de 7 dûÙgitos (IBGE) sûÈo sempre incluûÙdas.", en: "Municipality codes of 6 or 7 digits (IBGE). Applied independently from `city`; both the 6-digit (DATASUS) and 7-digit (IBGE) forms are always included.", es: "Cû°digos de municipio de 6 o 7 dûÙgitos (IBGE). Se aplica de forma independiente de `city`; siempre se incluyen tanto la forma de 6 dûÙgitos (DATASUS) como la de 7 dûÙgitos (IBGE)." },
    "use_cache": { pt: "Se TRUE (padrûÈo), usa dados em cache para evitar novos downloads. O cache ûˋ baseado nos parûÂmetros UF, ano, mûˆs e sistema.", en: "If TRUE (default), uses cached data to avoid re-downloads. The cache is based on the UF, year, month, and system parameters.", es: "Si es TRUE (predeterminado), usa datos en cachûˋ para evitar nuevas descargas. La cachûˋ se basa en los parûÀmetros UF, aûÝo, mes y sistema." },
    "cache_dir": { pt: "Diretû°rio onde os arquivos de cache sûÈo armazenados. O padrûÈo ûˋ \"~/.climasus4r_cache/data\".", en: "Directory where cached files are stored. Default is \"~/.climasus4r_cache/data\".", es: "Directorio donde se almacenan los archivos en cachûˋ. El valor predeterminado es \"~/.climasus4r_cache/data\"." },
    "force_redownload": { pt: "Se TRUE, ignora o cache e baixa tudo novamente. ûtil quando vocûˆ suspeita que os dados em cache estûÈo corrompidos ou desatualizados.", en: "If TRUE, ignores the cache and re-downloads everything. Useful when you suspect the cached data is corrupted or outdated.", es: "Si es TRUE, ignora la cachûˋ y vuelve a descargar todo. ûtil cuando sospecha que los datos en cachûˋ estûÀn daûÝados o desactualizados." },
    "parallel": { pt: "Se TRUE (padrûÈo), usa processamento paralelo para mû¤ltiplas combinaûÏûçes de UF/ano. Acelera consideravelmente downloads em massa.", en: "If TRUE (default), uses parallel processing for multiple UF/year combinations. Speeds up bulk downloads significantly.", es: "Si es TRUE (predeterminado), usa procesamiento paralelo para mû¤ltiples combinaciones de UF/aûÝo. Acelera considerablemente las descargas masivas." },
    "workers": { pt: "Nû¤mero de processos paralelos a usar. O padrûÈo ûˋ 4. Defina como 1 para desativar o processamento paralelo.", en: "Number of parallel workers to use. Default is 4. Set to 1 to disable parallel processing.", es: "Nû¤mero de procesos paralelos a usar. El valor predeterminado es 4. Defina 1 para desactivar el procesamiento paralelo." },
    "lang": { pt: "Idioma dos rû°tulos de variûÀveis e das mensagens. OpûÏûçes: `\"en\"` (inglûˆs), `\"pt\"` (portuguûˆs, padrûÈo), `\"es\"` (espanhol).", en: "Language for variable labels and messages. Options: `\"en\"` (English), `\"pt\"` (Portuguese, default), `\"es\"` (Spanish).", es: "Idioma de las etiquetas de variables y de los mensajes. Opciones: `\"en\"` (inglûˋs), `\"pt\"` (portuguûˋs, predeterminado), `\"es\"` (espaûÝol)." },
    "verbose": { pt: "Se TRUE (padrûÈo), exibe informaûÏûçes detalhadas de progresso, incluindo situaûÏûÈo do cache, progresso do download e estimativas de tempo.", en: "If TRUE (default), prints detailed progress information, including cache status, download progress, and time estimates.", es: "Si es TRUE (predeterminado), muestra informaciû°n detallada del progreso, incluyendo estado de la cachûˋ, progreso de la descarga y estimaciones de tiempo." },
