    "theme_style": { pt: "Reservado para futuras variantes de tema. Atualmente apenas `\"publication\"` (padrûÈo) estûÀ disponûÙvel.", en: "Reserved for future theme variants. Currently only `\"publication\"` (default) is available.", es: "Reservado para futuras variantes de tema. Actualmente solo `\"publication\"` (predeterminado) estûÀ disponible." },
