    "brazil_only": { pt: "Se deve filtrar o conjunto de dados global para a ûÀrea de abrangûˆncia do Brasil (longitude -75 a -28, latitude -35 a 6) antes do processamento. PadrûÈo `TRUE`.", en: "Whether to filter the global dataset to Brazil's bounding box (longitude -75 to -28, latitude -35 to 6) before processing. Default `TRUE`.", es: "Si se debe filtrar el conjunto de datos global al ûÀrea de cobertura de Brasil (longitud -75 a -28, latitud -35 a 6) antes del procesamiento. Predeterminado `TRUE`." },
